import React, { useState, useMemo } from 'react';

function ExpensiveCalculation() {
  const [count, setCount] = useState(1);
  const [otherState, setOtherState] = useState(0);

  const expensiveResult = useMemo(() => {
    console.log('Bahalı hesablama işləyir...');
    let result = 0;
    for (let i = 0; i < count * 1000000; i++) {
      result += i;
    }
    return result;
  }, [count]);

  return (
    <div>
      <p>Hesablama nəticəsi: {expensiveResult}</p>
      <button onClick={() => setCount(count + 1)}>Count artır (+1)</button>
      <button onClick={() => setOtherState(otherState + 1)}>Digər state artır ({otherState})</button>
    </div>
  );
}

console.log('useMemo ilə bahalı hesablama komponenti yaradıldı');

